INSERT INTO complaints (student_id, title, description, category, priority, status, resolution, assigned_to, resolved_at, created_at, updated_at) VALUES (1, 'Water leakage in bathroom', 'Continuous water leakage from bathroom ceiling pipe causing safety hazard.', 'PLUMBING', 'HIGH', 'RESOLVED', 'Pipe replaced by maintenance.', 'Mr. Rajendra', '2025-02-15 14:30:00', '2025-02-10 09:00:00', '2025-02-15 14:30:00');
INSERT INTO complaints (student_id, title, description, category, priority, status, resolution, assigned_to, resolved_at, created_at, updated_at) VALUES (3, 'WiFi issues on Ground Floor', 'WiFi signal extremely weak in rooms G-103 and G-104. Cannot attend online classes.', 'INTERNET', 'HIGH', 'IN_PROGRESS', NULL, 'IT Support Team', NULL, '2025-03-01 11:00:00', '2025-03-02 10:00:00');
INSERT INTO complaints (student_id, title, description, category, priority, status, resolution, assigned_to, resolved_at, created_at, updated_at) VALUES (5, 'Mess food quality dropped', 'Dinner meals quality has dropped significantly. Rice undercooked and vegetables bland.', 'FOOD', 'MEDIUM', 'OPEN', NULL, NULL, NULL, '2025-03-10 19:30:00', '2025-03-10 19:30:00');
